import{_ as t,o as a,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const k=JSON.parse('{"title":"TikTok SKAdNetwork","description":"","frontmatter":{"title":"TikTok SKAdNetwork","slug":"tiktok-skadnetwork"},"headers":[],"relativePath":"marketer-hub/tiktok-skadnetwork.md","filePath":"marketer-hub/tiktok-skadnetwork.md"}'),i={name:"marketer-hub/tiktok-skadnetwork.md"};function n(s,e,d,l,h,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The introduction of iOS 14.5 came with the rise of SKAdNetwork (SKAN) which had industry-wide impacts on the mobile measurement and attribution ecosystem. As such, TikTok For Business will work similarly to most non-self-attribution networks when it comes to SKAdNetwork campaigns.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><p>The Branch SDK can be used to manage all calls to SKAN. Once TikTok For Business is integrated and authenticated with Branch and the SDK is tracking events, TikTok For Business will forward individual SKAN Postbacks to Branch.</p><h2 id="tiktok-for-business-skan-support" tabindex="-1">TikTok For Business SKAN Support <a class="header-anchor" href="#tiktok-for-business-skan-support" aria-label="Permalink to &quot;TikTok For Business SKAN Support&quot;">​</a></h2><h3 id="supported-campaigns" tabindex="-1">Supported Campaigns <a class="header-anchor" href="#supported-campaigns" aria-label="Permalink to &quot;Supported Campaigns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>TikTok Campaign Type</th><th>SKAN Support for Branch</th></tr></thead><tbody><tr><td>TikTok App Install</td><td>✅</td></tr><tr><td>TikTok App Re-Engagement</td><td>❌ Does not support SKAN</td></tr></tbody></table><h3 id="apple-postback-data" tabindex="-1">Apple Postback Data <a class="header-anchor" href="#apple-postback-data" aria-label="Permalink to &quot;Apple Postback Data&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Supported</th></tr></thead><tbody><tr><td>Version</td><td>✅</td></tr><tr><td>Ad Network ID</td><td>✅</td></tr><tr><td>Campaign ID</td><td>✅</td></tr><tr><td>Transaction ID</td><td>✅</td></tr><tr><td>App ID</td><td>✅</td></tr><tr><td>Attribution Signature</td><td>✅</td></tr><tr><td>Redownload</td><td>✅</td></tr><tr><td>Source App ID</td><td>✅</td></tr><tr><td>Fidelity Type</td><td>✅</td></tr></tbody></table><h3 id="added-tiktok-data" tabindex="-1">Added TikTok Data <a class="header-anchor" href="#added-tiktok-data" aria-label="Permalink to &quot;Added TikTok Data&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Supported</th></tr></thead><tbody><tr><td>Campaign ID</td><td>✅</td></tr><tr><td>Campaign Name</td><td>✅</td></tr><tr><td>Ad Set ID</td><td>✅</td></tr><tr><td>Ad Set Name</td><td>✅</td></tr><tr><td>Ad ID</td><td>❌</td></tr><tr><td>Ad Name</td><td>❌</td></tr><tr><td>Creative ID</td><td>❌</td></tr><tr><td>Creative Name</td><td>❌</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable TikTok For Business SKAdNetwork, you need to have completed the following:</p><ol><li><a href="./enable-tiktok-for-business.html">Enable TikTok For Business</a></li><li>Access to Apple&#39;s developer tool.</li></ol><h2 id="enable-tiktok-skadnetwork" tabindex="-1">Enable TikTok SKAdNetwork <a class="header-anchor" href="#enable-tiktok-skadnetwork" aria-label="Permalink to &quot;Enable TikTok SKAdNetwork&quot;">​</a></h2><h3 id="_1-authenticate-skadnetwork-in-branch" tabindex="-1">1. Authenticate SKAdNetwork in Branch <a class="header-anchor" href="#_1-authenticate-skadnetwork-in-branch" aria-label="Permalink to &quot;1. Authenticate SKAdNetwork in Branch&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">DEVELOPER MAY BE REQUIRED</p><p>Authenticating your app requires access to Apple&#39;s developer tool <strong>App Store Connect</strong> as Branch requires several IDs and a key to complete authentication and sync the correct app to your Branch account.</p><ul><li>Issuer ID</li><li>Key ID</li><li>Private Key - <a href="https://developer.apple.com/documentation/appstoreconnectapi/creating_api_keys_for_app_store_connect_api" target="_blank" rel="noreferrer">learn how to generate a Private Key</a></li></ul></div><p>To configure SKAdNetwork functionality:</p><ol><li><p>Navigate to the <a href="https://dashboard.branch.io/skan-conversion/" target="_blank" rel="noreferrer">SKAN Conversion Center</a> page in the Branch Dashboard.</p></li><li><p>On this page, please provide the following App Store Connect information:<br> a. <strong>Issuer ID</strong><br> b. <strong>Key ID</strong><br> c. <strong>Private Key</strong></p></li><li><p>Once your fields are filled out and your Private Key file is uploaded, click the <strong>Authenticate &amp; Proceed To Configuration</strong> button.</p></li></ol><h4 id="resetting-credentials" tabindex="-1">Resetting Credentials <a class="header-anchor" href="#resetting-credentials" aria-label="Permalink to &quot;Resetting Credentials&quot;">​</a></h4><p>App Store Connect credentials are used as a one time check to verify app ownership. The SKAdNetwork integration is complete and valid as long as the app integration step is complete.</p><p>After this, the credentials may be removed. To remove them, click the <strong>Reset App Store Credentials</strong> button.</p><h3 id="_2-opt-in-for-branch-sdk-support" tabindex="-1">2. Opt-in for Branch SDK Support <a class="header-anchor" href="#_2-opt-in-for-branch-sdk-support" aria-label="Permalink to &quot;2. Opt-in for Branch SDK Support&quot;">​</a></h3><p>In the <strong>SKAdNetwork Config</strong> section of the <a href="https://dashboard.branch.io" target="_blank" rel="noreferrer">Branch dashboard</a>, select the <code>YES</code> radio button to have the Branch SDK handle all calls to SKAdNetwork.</p><p><strong>Do NOT opt-in if you decide to</strong>:</p><ul><li>Integrate directly with SKAdNetwork and <a href="./enable-skadnetwork.html">call the SKAdNetwork functions natively</a>.</li><li>Use another 3rd party library to handle your app&#39;s interactions with SKAdNetwork.</li></ul><h3 id="_3-assign-conversion-values-to-events" tabindex="-1">3. Assign Conversion Values to Events <a class="header-anchor" href="#_3-assign-conversion-values-to-events" aria-label="Permalink to &quot;3. Assign Conversion Values to Events&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">Custom Events</p><p>Custom Events need to be mapped in the <a href="https://dashboard.branch.io/ads/partner-management/a_tiktok?tab=settings" target="_blank" rel="noreferrer">TikTok For Business Events Config</a> so Branch can share the conversion value with TikTok.</p></div><ul><li>In the <code>SKAdNetwork Config</code> section of the <a href="https://dashboard.branch.io" target="_blank" rel="noreferrer">Branch dashboard</a>, select all app events you want Branch to send to Apple for attribution.</li><li>You may optionally select a Customer Event Alias and/or a Revenue Range to further distinguish the conversion value.</li><li>Assign unique values to each event (<em>Apple accepts any number from 0 to 63</em>) that represent their level of importance to you, where 63 is the highest priority and 0 is the lowest priority. Apple will always use the event with the highest priority, regardless if an event with a lower priority was tracked afterward.</li></ul><div class="info custom-block"><p class="custom-block-title">Revenue Range Guidance</p><ul><li>Revenue range is available for all Commerce Events where revenue is available on the event (Purchase, Add to Cart, Add to Wishlist, View Cart, Initiate Purchase, Add Payment Info, Click Ad, View Ad, Reserve, Spend Credits).</li><li>Revenue must be entered as USD on the dashboard. Branch will convert revenue with different currencies on events to USD.</li><li>Revenue ranges must not overlap for the same event (Ex: 1-100, 50-150).</li><li>Lower Bound Revenue is <em>inclusive</em>, Upper Bound Revenue is <em>exclusive</em>.</li><li>While not necessary, it is recommended to include both a lower + upper bound on every event.</li></ul></div><h2 id="skadnetwork-reporting" tabindex="-1">SKAdNetwork Reporting <a class="header-anchor" href="#skadnetwork-reporting" aria-label="Permalink to &quot;SKAdNetwork Reporting&quot;">​</a></h2><p>You may view performance of your SKAdNetwork Campaigns through the <a href="https://dashboard.branch.io/ads/skadnetwork/activity" target="_blank" rel="noreferrer">SKAdNetwork Activity Tab</a></p><p><em>[Image: 1451]</em></p><p>For additional details on the reporting capabilities, dimensions, etc. please see the following guides:</p><ul><li><a href="./skadnetwork-data.html">SKAdNetwork Data</a></li><li><a href="./skadnetwork-dashboard-reports.html">SKAdNetwork Analytics Dashboard</a></li></ul>',35)])])}const u=t(i,[["render",n]]);export{k as __pageData,u as default};
